@app.route('/api/cache/clear', methods=['POST'])
def clear_cache():
    data = request.get_json() or {}
    cache_type = data.get('type', 'all')
    
    if cache_type == 'all':
        memcache_client.flush_all()
        return jsonify({'message': 'All cache cleared'})
    else:
        return jsonify({'message': 'Specific cache pattern clearing not implemented'})

