@app.route('/api/cache/set', methods=['POST'])
def set_cache():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 300)
    
    if not key or value is None:
        return jsonify({'error': 'Key and value are required'}), 400
    
    memcache_client.set(key, value, expire=ttl)
    
    return jsonify({
        'message': 'Cache set successfully',
        'key': key,
        'ttl': ttl
    })

@app.route('/api/cache/get/<key>', methods=['GET'])
def get_cache(key):
    value = memcache_client.get(key)
    
    if value is None:
        return jsonify({'error': 'Key not found'}), 404
    
    return jsonify({
        'key': key,
        'value': value
    })

@app.route('/api/cache/delete/<key>', methods=['DELETE'])
def delete_cache(key):
    result = memcache_client.delete(key)
    
    return jsonify({
        'message': 'Cache deleted' if result else 'Key not found',
        'key': key,
        'deleted': result
    })

@app.route('/health', methods=['GET'])
def health_check():
    try:
        memcache_client.set('health_check', 'ok', expire=10)
        value = memcache_client.get('health_check')
        memcache_available = value == 'ok'
    except Exception as e:
        memcache_available = False
    
    return jsonify({
        'status': 'healthy' if memcache_available else 'degraded',
        'memcache': 'connected' if memcache_available else 'disconnected'
    })

